import axios from 'axios';

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || 'http://localhost:5000/api',
  timeout: 30000,
  headers: { 'Content-Type': 'application/json' },
});

api.interceptors.request.use(
  (config) => { const t=localStorage.getItem('accessToken'); if(t) config.headers.Authorization=`Bearer ${t}`; return config; },
  (error) => Promise.reject(error)
);

api.interceptors.response.use(
  (response) => response,
  async (error) => {
    const orig = error.config;
    if (error.response?.status===401 && !orig._retry) {
      orig._retry = true;
      const rt = localStorage.getItem('refreshToken');
      if (rt) {
        try {
          const { data } = await axios.post(`${api.defaults.baseURL}/auth/refresh`, { refreshToken:rt });
          localStorage.setItem('accessToken',  data.data.accessToken);
          localStorage.setItem('refreshToken', data.data.refreshToken);
          orig.headers.Authorization = `Bearer ${data.data.accessToken}`;
          return api(orig);
        } catch {
          localStorage.removeItem('accessToken');
          localStorage.removeItem('refreshToken');
          window.location.href = '/login';
        }
      }
    }
    return Promise.reject(error);
  }
);

// ── Student ───────────────────────────────────────────────
export const studentAPI = {
  getAll:   (params) => api.get('/students', { params }),
  getOne:   (id)     => api.get(`/students/${id}`),
  create:   (data)   => api.post('/students', data),
  update:   (id,d)   => api.put(`/students/${id}`, d),
  delete:   (id)     => api.delete(`/students/${id}`),
  promote:  (id,d)   => api.post(`/students/${id}/promote`, d),
};

// ── Enquiry ───────────────────────────────────────────────
export const enquiryAPI = {
  getAll:   (params) => api.get('/enquiries', { params }),
  getOne:   (id)     => api.get(`/enquiries/${id}`),
  create:   (data)   => api.post('/enquiries', data),
  update:   (id,d)   => api.put(`/enquiries/${id}`, d),
  delete:   (id)     => api.delete(`/enquiries/${id}`),
};

// ── Registration ──────────────────────────────────────────
export const registrationAPI = {
  getAll:   (params) => api.get('/registrations', { params }),
  create:   (data)   => api.post('/registrations', data),
  update:   (id,d)   => api.put(`/registrations/${id}`, d),
  convert:  (id)     => api.post(`/registrations/${id}/convert`),
};

// ── Fee ───────────────────────────────────────────────────
export const feeAPI = {
  getStructure:   (params) => api.get('/fees/structure', { params }),
  getStudentFees: (sid)    => api.get(`/fees/student/${sid}`),
  collect:        (data)   => api.post('/fees/collect', data),
  getCollection:  (params) => api.get('/fees/collection-report', { params }),
  getPending:     (params) => api.get('/fees/pending', { params }),
};

// ── Attendance ────────────────────────────────────────────
export const attendanceAPI = {
  mark:       (data)          => api.post('/attendance/student/mark', data),
  getClass:   (params)        => api.get('/attendance/student/class', { params }),
  getMonthly: (sid, params)   => api.get(`/attendance/student/${sid}/monthly`, { params }),
  getReport:  (params)        => api.get('/attendance/report', { params }),
};

// ── Dashboard ─────────────────────────────────────────────
export const dashboardAPI = {
  get: () => api.get('/dashboard'),
};

// ── Notice ────────────────────────────────────────────────
export const noticeAPI = {
  getAll:  (params) => api.get('/notices', { params }),
  create:  (data)   => api.post('/notices', data),
  delete:  (id)     => api.delete(`/notices/${id}`),
};

// ── Employee ──────────────────────────────────────────────
export const employeeAPI = {
