  getProfile:      ()       => api.get('/schools/profile'),
  updateProfile:   (data)   => api.put('/schools/profile', data),
  getClasses:      ()       => api.get('/schools/classes'),
  getSections:     (params) => api.get('/schools/sections', { params }),
  getSubjects:     ()       => api.get('/schools/subjects'),
  getAcademicYears:()       => api.get('/schools/academic-years'),
};

// ── Report ────────────────────────────────────────────────
export const reportAPI = {
  getFeeSummary:        (params) => api.get('/reports/fee-summary',          { params }),
  getAttendanceSummary: (params) => api.get('/reports/attendance-summary',   { params }),
  getStudentStrength:   (params) => api.get('/reports/student-strength',     { params }),
};

// ── Transport ─────────────────────────────────────────────
export const transportAPI = {
  getRoutes:   ()     => api.get('/transport/routes'),
  getVehicles: ()     => api.get('/transport/vehicles'),
  createRoute: (data) => api.post('/transport/routes', data),
};

// ── Library ───────────────────────────────────────────────
export const libraryAPI = {
  getBooks:   (params) => api.get('/library/books', { params }),
  issueBook:  (data)   => api.post('/library/issue', data),
  returnBook: (id)     => api.put(`/library/return/${id}`),
};

// ── Payroll ───────────────────────────────────────────────
export const payrollAPI = {
  getAll:   (params) => api.get('/payroll', { params }),
  process:  (data)   => api.post('/payroll', data),
};

export default api;
